/// Tool details of a tool that the model may use to generate a response.
@available(iOS 15.0, macOS 13.0, macCatalyst 15.0, tvOS 15.0, watchOS 8.0, *)
public struct Tool: Sendable {
  /// Optional. Retrieval tool type. System will always execute the provided retrieval
  /// tool(s) to get external knowledge to answer the prompt. Retrieval results are
  /// presented to the model for generation. This field is not supported in Gemini
  /// API.
  public let retrieval: Retrieval?

  /// Optional. Tool to support the model interacting directly with the
  /// computer. If enabled, it automatically populates computer-use specific
  /// Function Declarations.
  public let computerUse: ComputerUse?

  /// Optional. FileSearch tool type. Tool to retrieve knowledge from Semantic
  /// Retrieval corpora. This field is not supported in Vertex AI.
  public let fileSearch: FileSearch?

  /// Optional. GoogleSearch tool type. Tool to support Google Search in Model.
  /// Powered by Google.
  public let googleSearch: GoogleSearch?

  /// Optional. Tool that allows grounding the model's response with
  /// geospatial context related to the user's query.
  public let googleMaps: GoogleMaps?

  /// Optional. CodeExecution tool type. Enables the model to execute code as part of
  /// generation.
  public let codeExecution: ToolCodeExecution?

  /// Optional. Tool to support searching public web data, powered by Vertex AI Search
  /// and Sec4 compliance. This field is not supported in Gemini API.
  public let enterpriseWebSearch: EnterpriseWebSearch?

  /// Optional. Function tool type. One or more function declarations to be passed to
  /// the model along with the current user query. Model may decide to call a subset
  /// of these functions by populating FunctionCall in the response. User should
  /// provide a FunctionResponse for each function call in the next turn. Based on the
  /// function responses, Model will generate the final response back to the user.
  /// Maximum 512 function declarations can be provided.
  public let functionDeclarations: [FunctionDeclaration]?

  /// Optional. Specialized retrieval tool that is powered by Google Search.
  public let googleSearchRetrieval: GoogleSearchRetrieval?

  /// Optional. If specified, Vertex AI will use Parallel.ai to search for information
  /// to answer user queries. The search results will be grounded on Parallel.ai and
  /// presented to the model for response generation. This field is not supported in
  /// Gemini API.
  public let parallelAiSearch: ToolParallelAiSearch?

  /// Optional. Tool to support URL context retrieval.
  public let urlContext: UrlContext?

  /// Optional. MCP Servers to connect to. This field is not supported in Vertex AI.
  public let mcpServers: [McpServer]?

  /// Default initializer.
  public init(
    retrieval: Retrieval? = nil,
    computerUse: ComputerUse? = nil,
    fileSearch: FileSearch? = nil,
    googleSearch: GoogleSearch? = nil,
    googleMaps: GoogleMaps? = nil,
    codeExecution: ToolCodeExecution? = nil,
    enterpriseWebSearch: EnterpriseWebSearch? = nil,
    functionDeclarations: [FunctionDeclaration]? = nil,
    googleSearchRetrieval: GoogleSearchRetrieval? = nil,
    parallelAiSearch: ToolParallelAiSearch? = nil,
    urlContext: UrlContext? = nil,
    mcpServers: [McpServer]? = nil
  ) {
    self.retrieval = retrieval
    self.computerUse = computerUse
    self.fileSearch = fileSearch
    self.googleSearch = googleSearch
    self.googleMaps = googleMaps
    self.codeExecution = codeExecution
    self.enterpriseWebSearch = enterpriseWebSearch
    self.functionDeclarations = functionDeclarations
    self.googleSearchRetrieval = googleSearchRetrieval
    self.parallelAiSearch = parallelAiSearch
    self.urlContext = urlContext
    self.mcpServers = mcpServers
  }
}

