@available(iOS 15.0, macOS 13.0, macCatalyst 15.0, tvOS 15.0, watchOS 8.0, *)
public struct DatasetStats: Sendable {
  /// Output only. A partial sample of the indices (starting from 1) of the dropped
  /// examples.
