    labels: [String: String]? = nil,
    beta: Float? = nil,
    baseTeacherModel: String? = nil,
    tunedTeacherModelSource: String? = nil,
    sftLossWeightMultiplier: Float? = nil,
    outputUri: String? = nil,
    encryptionSpec: EncryptionSpec? = nil
  ) {
    self.httpOptions = httpOptions
    self.method = method
