/// Incremental server update generated by the model in response to client messages.
///
/// Content is generated as quickly as possible, and not in real time. Clients
/// may choose to buffer and play it out in real time.
@available(iOS 15.0, macOS 13.0, macCatalyst 15.0, tvOS 15.0, watchOS 8.0, *)
public struct LiveServerContent: Sendable {
  /// The content that the model has generated as part of the current conversation
  /// with the user.
  public let modelTurn: Content?

  /// If true, indicates that the model is done generating. Generation will only start
  /// in response to additional client messages. Can be set alongside `content`,
  /// indicating that the `content` is the last in the turn.
  public let turnComplete: Bool?

  /// If true, indicates that a client message has interrupted current model
  /// generation. If the client is playing out the content in realtime, this is a good
  /// signal to stop and empty the current queue.
  public let interrupted: Bool?

  /// Metadata returned to client when grounding is enabled.
  public let groundingMetadata: GroundingMetadata?

  /// If true, indicates that the model is done generating. When model is
  /// interrupted while generating there will be no generation_complete message
  /// in interrupted turn, it will go through interrupted > turn_complete.
  /// When model assumes realtime playback there will be delay between
  /// generation_complete and turn_complete that is caused by model
  /// waiting for playback to finish. If true, indicates that the model
  /// has finished generating all content. This is a signal to the client
  /// that it can stop sending messages.
  public let generationComplete: Bool?

  /// Input transcription. The transcription is independent to the model
  /// turn which means it doesn’t imply any ordering between transcription and
  /// model turn.
  public let inputTranscription: Transcription?

  /// Output transcription. The transcription is independent to the model
  /// turn which means it doesn’t imply any ordering between transcription and
  /// model turn.
  public let outputTranscription: Transcription?

  /// Metadata related to url context retrieval tool.
  public let urlContextMetadata: UrlContextMetadata?

  /// Reason for the turn is complete.
  public let turnCompleteReason: TurnCompleteReason?

  /// If true, indicates that the model is not generating content because
  /// it is waiting for more input from the user, e.g. because it expects the
  /// user to continue talking.
  public let waitingForInput: Bool?

  /// Default initializer.
  public init(
    modelTurn: Content? = nil,
    turnComplete: Bool? = nil,
    interrupted: Bool? = nil,
    groundingMetadata: GroundingMetadata? = nil,
    generationComplete: Bool? = nil,
    inputTranscription: Transcription? = nil,
    outputTranscription: Transcription? = nil,
    urlContextMetadata: UrlContextMetadata? = nil,
    turnCompleteReason: TurnCompleteReason? = nil,
    waitingForInput: Bool? = nil
  ) {
    self.modelTurn = modelTurn
    self.turnComplete = turnComplete
    self.interrupted = interrupted
    self.groundingMetadata = groundingMetadata
    self.generationComplete = generationComplete
    self.inputTranscription = inputTranscription
    self.outputTranscription = outputTranscription
    self.urlContextMetadata = urlContextMetadata
    self.turnCompleteReason = turnCompleteReason
    self.waitingForInput = waitingForInput
  }
}

