/// Configures automatic detection of activity.
@available(iOS 15.0, macOS 13.0, macCatalyst 15.0, tvOS 15.0, watchOS 8.0, *)
public struct AutomaticActivityDetection: Sendable {
  /// If enabled, detected voice and text input count as activity. If disabled, the
  /// client must send activity signals.
  public let disabled: Bool?

  /// Determines how likely speech is to be detected.
  public let startOfSpeechSensitivity: StartSensitivity?

  /// Determines how likely detected speech is ended.
  public let endOfSpeechSensitivity: EndSensitivity?

  /// The required duration of detected speech before start-of-speech is committed.
  /// The lower this value the more sensitive the start-of-speech detection is and the
  /// shorter speech can be recognized. However, this also increases the probability
  /// of false positives.
  public let prefixPaddingMs: Int32?

  /// The required duration of detected non-speech (e.g. silence) before end-of-speech
  /// is committed. The larger this value, the longer speech gaps can be without
  /// interrupting the user's activity but this will increase the model's latency.
  public let silenceDurationMs: Int32?

  /// Default initializer.
  public init(
    disabled: Bool? = nil,
    startOfSpeechSensitivity: StartSensitivity? = nil,
    endOfSpeechSensitivity: EndSensitivity? = nil,
    prefixPaddingMs: Int32? = nil,
    silenceDurationMs: Int32? = nil
  ) {
    self.disabled = disabled
    self.startOfSpeechSensitivity = startOfSpeechSensitivity
    self.endOfSpeechSensitivity = endOfSpeechSensitivity
    self.prefixPaddingMs = prefixPaddingMs
    self.silenceDurationMs = silenceDurationMs
  }
}

