/// Session config for the API connection.
@available(iOS 15.0, macOS 13.0, macCatalyst 15.0, tvOS 15.0, watchOS 8.0, *)
public struct LiveConnectConfig: Sendable {
  /// Used to override HTTP request options.
  public let httpOptions: HttpOptions?

  /// The generation configuration for the session.
  public let generationConfig: GenerationConfig?

  /// The requested modalities of the response. Represents the set of
  /// modalities that the model can return. Defaults to AUDIO if not specified.
  public let responseModalities: [Modality]?

  /// Value that controls the degree of randomness in token selection.
  /// Lower temperatures are good for prompts that require a less open-ended or
  /// creative response, while higher temperatures can lead to more diverse or
  /// creative results.
  public let temperature: Float?

  /// Tokens are selected from the most to least probable until the sum
  /// of their probabilities equals this value. Use a lower value for less
  /// random responses and a higher value for more random responses.
  public let topP: Float?

  /// For each token selection step, the ``top_k`` tokens with the
  /// highest probabilities are sampled. Then tokens are further filtered based
  /// on ``top_p`` with the final token selected using temperature sampling. Use
  /// a lower number for less random responses and a higher number for more
  /// random responses.
  public let topK: Float?

  /// Maximum number of tokens that can be generated in the response.
  public let maxOutputTokens: Int32?

  /// If specified, the media resolution specified will be used.
  public let mediaResolution: MediaResolution?

  /// When ``seed`` is fixed to a specific number, the model makes a best
  /// effort to provide the same response for repeated requests. By default, a
  /// random number is used.
  public let seed: Int32?

  /// The speech generation configuration.
  public let speechConfig: SpeechConfig?

  /// Config for thinking features.
  /// An error will be returned if this field is set for models that don't
  /// support thinking.
  public let thinkingConfig: ThinkingConfig?

  /// If enabled, the model will detect emotions and adapt its responses accordingly.
  public let enableAffectiveDialog: Bool?

  /// The user provided system instructions for the model.
  /// Note: only text should be used in parts and content in each part will be
  /// in a separate paragraph.
  public let systemInstruction: [Content]?

  /// A list of `Tools` the model may use to generate the next response.
  ///
  /// A `Tool` is a piece of code that enables the system to interact with
  /// external systems to perform an action, or set of actions, outside of
  /// knowledge and scope of the model.
  public let tools: [Tool]?

  /// Configures session resumption mechanism.
  ///
  /// If included the server will send SessionResumptionUpdate messages.
  public let sessionResumption: SessionResumptionConfig?

  /// The transcription of the input aligns with the input audio language.
  public let inputAudioTranscription: AudioTranscriptionConfig?

  /// The transcription of the output aligns with the language code
  /// specified for the output audio.
  public let outputAudioTranscription: AudioTranscriptionConfig?

  /// Configures the realtime input behavior in BidiGenerateContent.
  public let realtimeInputConfig: RealtimeInputConfig?

  /// Configures context window compression mechanism.
  ///
  /// If included, server will compress context window to fit into given length.
  public let contextWindowCompression: ContextWindowCompressionConfig?

  /// Configures the proactivity of the model. This allows the model to respond
  /// proactively to
  /// the input and to ignore irrelevant input.
  public let proactivity: ProactivityConfig?

  /// Configures the explicit VAD signal. If enabled, the client will send
  /// vad_signal to indicate the start and end of speech. This allows the server
  /// to process the audio more efficiently.
  public let explicitVadSignal: Bool?

  /// Default initializer.
  public init(
    httpOptions: HttpOptions? = nil,
    generationConfig: GenerationConfig? = nil,
    responseModalities: [Modality]? = nil,
    temperature: Float? = nil,
    topP: Float? = nil,
    topK: Float? = nil,
    maxOutputTokens: Int32? = nil,
    mediaResolution: MediaResolution? = nil,
    seed: Int32? = nil,
    speechConfig: SpeechConfig? = nil,
    thinkingConfig: ThinkingConfig? = nil,
    enableAffectiveDialog: Bool? = nil,
    systemInstruction: [Content]? = nil,
    tools: [Tool]? = nil,
    sessionResumption: SessionResumptionConfig? = nil,
    inputAudioTranscription: AudioTranscriptionConfig? = nil,
    outputAudioTranscription: AudioTranscriptionConfig? = nil,
    realtimeInputConfig: RealtimeInputConfig? = nil,
    contextWindowCompression: ContextWindowCompressionConfig? = nil,
    proactivity: ProactivityConfig? = nil,
    explicitVadSignal: Bool? = nil
  ) {
    self.httpOptions = httpOptions
    self.generationConfig = generationConfig
    self.responseModalities = responseModalities
    self.temperature = temperature
    self.topP = topP
    self.topK = topK
    self.maxOutputTokens = maxOutputTokens
    self.mediaResolution = mediaResolution
    self.seed = seed
    self.speechConfig = speechConfig
    self.thinkingConfig = thinkingConfig
    self.enableAffectiveDialog = enableAffectiveDialog
    self.systemInstruction = systemInstruction
    self.tools = tools
    self.sessionResumption = sessionResumption
    self.inputAudioTranscription = inputAudioTranscription
    self.outputAudioTranscription = outputAudioTranscription
    self.realtimeInputConfig = realtimeInputConfig
    self.contextWindowCompression = contextWindowCompression
    self.proactivity = proactivity
    self.explicitVadSignal = explicitVadSignal
  }
}

